<template>
  <div>
    <img style="width: 100%; height: 100%" src="../../assets/img/chat_bg.jpg" />

    <div class="abs cover contaniner" id="app">
      <div class="abs cover pnl">
        <div class="top pnl-head" style="padding: 20px; color: white">
          <div id="userName">
            当前用户：{{ username }}
            <span style="float: right; color: green" v-if="isOnline">在线</span>
            <span style="float: right; color: red" v-else>离线</span>
          </div>
          <div
            id="chatMes"
            v-show="chatMes"
            style="text-align: center; color: #6fbdf3; font-family: 新宋体"
          >
            <div v-show="isFriend">
              正在和<font face="楷体">{{ toName }}</font
              >聊天
            </div>
            <div v-show="!isFriend">群聊中</div>
          </div>
        </div>
        <!--聊天区开始-->
        <div class="abs cover pnl-body" id="pnlBody">
          <div
            class="abs cover pnl-left"
            id="initBackground"
            style="background-color: white; width: 100%"
          >
            <div class="abs cover pnl-left" id="chatArea" v-show="isShowChat">
              <div
                class="abs cover pnl-msgs scroll"
                ref="historyMessage"
                id="show"
              >
                <div class="pnl-list" id="hists"><!-- 历史消息 --></div>
                <div
                  class="pnl-list"
                  id="msgs"
                  v-for="(message, index) in historyMessage"
                  :key="index"
                >
                  <!-- 消息这展示区域 -->
                  <div class="msg guest" v-if="message.fromName == username">
                    <div class="msg-right">
                      <div class="msg-host headDefault"></div>
                      <div class="msg-ball">{{ message.message }}</div>
                    </div>
                  </div>
                  <div class="msg robot" v-else>
                    <div class="msg-left" worker="">
                      <div class="msg-host headDefault"></div>
                      <div class="username">{{ message.fromName }}</div>
                      <div class="msg-ball">{{ message.message }}</div>
                    </div>
                  </div>
                </div>
              </div>

              <div class="abs bottom pnl-text">
                <div class="abs cover pnl-input">
                  <textarea
                    class="scroll"
                    id="context_text"
                    @keydown.enter="handleSendButton"
                    wrap="hard"
                    placeholder="在此输入文字信息..."
                    v-model="sendMessage.message"
                  ></textarea>

                  <div class="abs atcom-pnl scroll hide" id="atcomPnl">
                    <ul class="atcom" id="atcom"></ul>
                  </div>
                </div>
                <div
                  class="abs br pnl-btn"
                  id="submit"
                  @click="handleLogoutButton"
                  style="
                 
                    background-color: rgb(202, 32, 32);
                    color: rgb(255, 255, 255);
                    margin-right:100px;
                  "
                >
                  退出登录
                </div>
                <div
                  class="abs br pnl-btn"
                  id="submit"
                  @click="handleSendButton"
                  style="
                    background-color: rgb(32, 196, 202);
                    color: rgb(255, 255, 255);
                  "
                >
                  发送
                </div>
                <div class="pnl-support" id="copyright">
                  <a>辱骂李昊阳专属</a>
                </div>
              </div>
            </div>

            <!--聊天区 结束-->
            <div class="abs right pnl-right">
              <div class="slider-container hide"></div>
              <div class="pnl-right-content">
                <div class="pnl-tabs">
                  <div class="tab-btn active" id="hot-tab">好友列表</div>
                </div>
                <div class="pnl-hot">
                  <ul class="rel-list unselect">
                    <li
                      class="rel-item"
                      v-for="friend in friendsList"
                      :key="friend"
                    >
                      <a @click="showChat(friend)">{{ friend }}</a>
                      <!-- <a>{{ friend }}</a> -->
                    </li>
                  </ul>
                </div>
              </div>

              <div class="pnl-right-content">
                <div class="pnl-tabs">
                  <div class="tab-btn active">系统广播</div>
                </div>
                <div class="pnl-hot">
                  <ul class="rel-list unselect" id="broadcastList">
                    <li
                      class="rel-item"
                      style="color: #9d9d9d; font-family: 宋体"
                      v-for="(name, index) in systemMessages"
                      :key="index"
                    >
                      您的好友 {{ name }} 已上线
                    </li>
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { getUsername, removeUsername,getToken,removeToken } from "@/utils/username";
import axios from "axios";

export default {
  name: "HomeView",
  data() {
    return {
      isFriend: false,
      toName: "",
      sendMessage: {
        toName: "",
        message: "",
      },
      historyMessage: [],
      isOnline: true,
      chatMes: true,
      isShowChat: true,
      systemMessages: [],
      webSocketObject: null,
      username: "",
      
      messageList: [],
      friendsList: [],
    };
  },
  created() {
    
  },
  mounted() {
    //从localStorage中获得username
    this.username = getUsername();
    //如果username不存在返回到登录页面
    if (!this.username) {
      this.$router.push({
        name: "Login",
      });
    }
    //初始化WebSocket
    this.webSocketInit();
    this.findByFriend("");
  },

  beforeDestroy() {
    this.webSocketObject.close(); //在该组件销毁时关闭该连接以节约资源
  },
  methods: {
    findByFriend(toName) {
      const token=getToken();
      axios
        .get(
          "http://47.99.45.73:8000/message?fromName=" +
            this.username +
            "&&toName=" +
            toName,
            {
              headers:{
                "Authorization":token
              }
            }
        )
        .then((resp) => {
          this.historyMessage = resp.data.data;
        });
      this.$nextTick(() => {
        // 使用 $refs 获取到 historyMessage 元素
        const historyMessage = this.$refs.historyMessage;

        // 滚动到滚动条最下方
        historyMessage.scrollTop = historyMessage.scrollHeight;
      });
    },
    showChat(name) {
      this.isFriend = true;
      this.toName = name;
      this.sendMessage.toName = name;
      this.findByFriend(name);
      //清除聊天区的数据
      // let history = sessionStorage.getItem(this.toName);
      // if (!history) {
      //   this.historyMessage = [];
      // } else {
      //   this.historyMessage = JSON.parse(history);
      // }
      // //展示聊天对话框
      // this.isShowChat = true;
      // //显示“正在和谁聊天”
      // this.chatMes = true;
    },
    webSocketInit() {
      // const token=getToken();
      const webSocketUrl = "ws://47.99.45.73:8000/websocket/" + this.username;
      this.webSocketObject = new WebSocket(webSocketUrl); 
      this.webSocketObject.onopen = this.webSocketOnOpen;
      this.webSocketObject.onmessage = this.webSocketOnMessage;
      this.webSocketObject.onerror = this.webSocketOnError;
      this.webSocketObject.onclose = this.webSocketOnClose;
    },
    webSocketOnOpen(e) {
      console.log("与服务端连接打开->", e);
    },
    webSocketOnMessage(e) {
      console.log("来自服务端的消息->", e);
      const receiveMessage = JSON.parse(e.data);
      if (receiveMessage.system) {
        //系统消息  好友列表展示
        var names = receiveMessage.message;
        this.friendsList = [];
        this.systemMessages = [];
        for (let i = 0; i < names.length; i++) {
          if (names[i] != this.username) {
            this.friendsList.push(names[i]);
            this.systemMessages.push(names[i]);
          }
        }
      } else {
        // if (receiveMessage.username != this.username) {
        //   this.toName = receiveMessage.username;
        // }
        if (
          (receiveMessage.toName == this.toName &&
            receiveMessage.fromName == this.username) ||
          (receiveMessage.fromName == this.toName &&
            receiveMessage.toName == this.username)
        ) {
          this.historyMessage.push(receiveMessage);
        }
      }
      this.$nextTick(() => {
        // 使用 $refs 获取到 historyMessage 元素
        const historyMessage = this.$refs.historyMessage;

        // 滚动到滚动条最下方
        historyMessage.scrollTop = historyMessage.scrollHeight;
      });
    },
    webSocketOnError(e) {
      console.log("与服务端连接异常->", e);
    },
    webSocketOnClose(e) {
      console.log("与服务端连接关闭->", e);
    },
    handleSendButton(event) {
      event.preventDefault();
      if (this.sendMessage.message != null && this.sendMessage.message != ""&&this.sendMessage.message.trim().length>0) {
        const fromName = this.username;
        const message = this.sendMessage.message;
        const toName = this.sendMessage.toName;
        this.webSocketObject.send(
          JSON.stringify({
            id: 1,
            message,
            fromName,
            toName,
            time: new Date().getTime(),
          })
        );
        this.sendMessage.message = "";
      } else {
        this.$message({
          message: "消息不能为空",
          type: "warning",
        });
      }
    },
    handleLogoutButton() {
      removeUsername(); //清除username然后断开连接
      removeToken();
      this.webSocketObject.close();
      this.$router.push({
        name: "Login",
      });
    },
  },
};
</script>

<style scoped>
@import "../../assets/css/chat.css";
</style>
